    """Check that the video has the expected dimensions."""
    info = ffprobe_json(filepath)
    if not info:
        return False
    for stream in info.get("streams", []):
        if stream.get("codec_type") == "video":
            w = stream.get("width")
            h = stream.get("height")
            if w == expected_w and h == expected_h:
                return True
    return False

